/* Zebra Coffee Co. Stylesheet */

/* ==========================================
   CSS Variables & Themes
   ========================================== */
:root {
  /* Colors (Light Theme Defaults) */
  --bg-color: #fcf9f5;
  --bg-card: #ffffff;
  --text-primary: #2d251e;
  --text-secondary: #6e5e53;
  --primary-color: #c07d4c;
  --primary-hover: #a36233;
  --accent-color: #eddcd2;
  --accent-text: #603a1d;
  --border-color: #e6ded6;
  --shadow-sm: 0 2px 4px rgba(45, 37, 30, 0.05);
  --shadow-md: 0 10px 20px rgba(45, 37, 30, 0.08);
  --shadow-lg: 0 15px 35px rgba(45, 37, 30, 0.12);

  /* Fonts */
  --font-serif: 'Playfair Display', Georgia, serif;
  --font-sans: 'Poppins', system-ui, -apple-system, sans-serif;

  /* Transitions */
  --transition-fast: 0.2s ease;
  --transition-normal: 0.3s ease;
  --transition-slow: 0.5s cubic-bezier(0.16, 1, 0.3, 1);

  /* Spacing & Border Radius */
  --radius-sm: 6px;
  --radius-md: 12px;
  --radius-lg: 20px;
  --radius-circle: 50%;
  --container-width: 1200px;
}

/* Dark Theme Variables */
[data-theme="dark"] {
  --bg-color: #120e0b;
  --bg-card: #1c1612;
  --text-primary: #f5eedb;
  --text-secondary: #b5a497;
  --primary-color: #d68f5c;
  --primary-hover: #ebd0a0;
  --accent-color: #2c211a;
  --accent-text: #eddcd2;
  --border-color: #2e241c;
  --shadow-sm: 0 2px 4px rgba(0, 0, 0, 0.3);
  --shadow-md: 0 10px 20px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 15px 35px rgba(0, 0, 0, 0.5);
}

/* ==========================================
   Base Styles & Reset
   ========================================== */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
}

body {
  font-family: var(--font-sans);
  background-color: var(--bg-color);
  color: var(--text-primary);
  line-height: 1.6;
  transition: background-color var(--transition-normal), color var(--transition-normal);
  overflow-x: hidden;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  text-decoration: none;
  color: inherit;
  transition: color var(--transition-fast);
}

button, input {
  font-family: inherit;
  border: none;
  outline: none;
}

ul {
  list-style: none;
}

/* ==========================================
   Re-usable Utility Classes
   ========================================== */
.container {
  width: 90%;
  max-width: var(--container-width);
  margin: 0 auto;
}

.text-center {
  text-align: center;
}

.grid-3 {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
}

.grid-4 {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 2rem;
}

.flex-space-between {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

/* Section Common Styles */
section {
  padding: 6rem 0;
}

.section-header {
  margin-bottom: 4rem;
}

.section-subtitle {
  font-family: var(--font-serif);
  font-size: 1.2rem;
  font-style: italic;
  color: var(--primary-color);
  display: block;
  margin-bottom: 0.5rem;
  font-weight: 600;
}

.section-title {
  font-family: var(--font-serif);

/**
 * Reverses a given string.
 * @param str The string to reverse.
 * @returns The reversed string.
 */
export function reverseString(str: string): string {
  return str.split('').reverse().join('');
}

