{"content":"/* ==========================================
   Zebra Academy - Premium Stylesheet
   ========================================== */

/* Theme Configuration */
:root {
  /* Light Theme Variables */
  --bg-color: #f8fafc;
  --bg-card: #ffffff;
  --bg-card-alt: #f1f5f9;
  --text-primary: #0f172a;
  --text-secondary: #475569;
  --text-muted: #94a3b8;

  --primary-color: #6366f1; /* Indigo */
  --primary-hover: #4f46e5;
  --primary-rgb: 99, 102, 241;

  --accent-color: #06b6d4; /* Cyan */
  --accent-hover: #0891b2;
  --accent-rgb: 6, 182, 212;

  --success-color: #10b981; /* Emerald */
  --warning-color: #f59e0b; /* Amber */
  --danger-color: #ef4444; /* Rose */

  --border-color: #e2e8f0;
  --border-focus: #cbd5e1;

  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -2px rgba(0, 0, 0, 0.1);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -4px rgba(0, 0, 0, 0.1);
  --shadow-xl: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 8px 10px -6px rgba(0, 0, 0, 0.1);

  --font-sans: 'Plus Jakarta Sans', system-ui, -apple-system, sans-serif;
  --font-serif: 'Playfair Display', Georgia, serif;

  /* Layout */
  --container-width: 1240px;
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 20px;
  --radius-xl: 30px;
  --transition-fast: 0.15s ease;
  --transition-normal: 0.3s ease;
  --transition-slow: 0.6s cubic-bezier(0.16, 1, 0.3, 1);
}

[data-theme="dark"] {
  /* Dark Theme Variables */
  --bg-color: #0b0f19;
  --bg-card: #131b2e;
  --bg-card-alt: #1e293b;
  --text-primary: #f8fafc;
  --text-secondary: #94a3b8;
  --text-muted: #64748b;

  --primary-color: #818cf8;
  --primary-hover: #6366f1;
  --primary-rgb: 129, 140, 248;

  --accent-color: #22d3ee;
  --accent-hover: #06b6d4;
  --accent-rgb: 34, 211, 238;

  --border-color: #1e293b;
  --border-focus: #334155;

  --shadow-sm: 0 2px 4px rgba(0, 0, 0, 0.2);
  --shadow-md: 0 8px 16px rgba(0, 0, 0, 0.3);
  --shadow-lg: 0 16px 32px rgba(0, 0, 0, 0.4);
  --shadow-xl: 0 24px 48px rgba(0, 0, 0, 0.5);
}

/* Base Reset */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
}

body {
  font-family: var(--font-sans);
  background-color: var(--bg-color);
  color: var(--text-primary);
  line-height: 1.6;
  overflow-x: hidden;
  transition: background-color var(--transition-normal), color var(--transition-normal);
}

/* Typography elements */
h1, h2, h3, h4, h5, h6 {
  font-weight: 700;
  line-height: 1.25;
  letter-spacing: -0.02em;
}

p {
  color: var(--text-secondary);
}

a {
  text-decoration: none;
  color: inherit;
  transition: color var(--transition-fast), background-color var(--transition-fast);
}

button {
  cursor: pointer;
  border: none;
  outline: none;
  background: none;
  font-family: inherit;
  transition: all var(--transition-fast);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

ul {
  list-style: none;
}

/* ==========================================
   Utility / Layout Helper Classes
   ========================================== */
.container {
  width: 90%;
  max-width: var(--container-width);
  margin: 0 auto;
}

.text-center {
  text-align: center;
}

.text-gradient {
  background: linear-gradient(135deg, var(--primary-color), var(--accent-color));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.grid-3 {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 2.5rem;
}

.hide {
  display: none !important;
}

.text-success { color: var(--success-color); }
.text-warning { color: var(--warning-color); }
.text-danger { color: var(--danger-color); }
.text-purple { color: #818cf8; }
.text-orange { color: #f97316; }

/* Sections */
section {
  padding: 8rem 0;
}

.section-header {
  margin-bottom: 4rem;
  max-width: 700px;
  margin-left: auto;
  margin-right: auto;
}

.section-header-flex {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  gap: 2rem;
  margin-bottom: 3.5rem;
  flex-wrap: wrap;
}

.section-subtitle {
  font-weight: 700;
  color: var(--primary-color);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  font-size: 0.85rem;
  margin-bottom: 0.75rem;
  display: inline-block;
}

.section-title {
  font-size: 2.5rem;
  margin-bottom: 1rem;
}

.section-desc {
  font-size: 1.15rem;
  color: var(--text-secondary);
  font-weight: 400;
}

/* ==========================================
   Buttons & Inputs
   ========================================== */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  font-size: 0.95rem;
  font-weight: 600;
  padding: 0.75rem 1.5rem;
  border-radius: var(--radius-sm);
  transition: all var(--transition-fast);
}

.btn-primary {
  background-color: var(--primary-color);
  color: white;
  box-shadow: 0 4px 14px rgba(var(--primary-rgb), 0.3);
}

.btn-primary:hover {
  background-color: var(--primary-hover);
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(var(--primary-rgb), 0.4);
}

.btn-secondary {
  background-color: var(--bg-card-alt);
  color: var(--text-primary);
  border: 1px solid var(--border-color);
}

.btn-secondary:hover {
  background-color: var(--border-color);
  transform: translateY(-2px);
}

.btn-primary-outline {
  border: 2px solid var(--primary-color);
  color: var(--primary-color);
}

.btn-primary-outline:hover {
  background-color: var(--primary-color);
  color: white;
}

.btn-full {
  width: 100%;
}

.btn-success-glow:hover {
  box-shadow: 0 0 20px rgba(16, 185, 129, 0.4);
  background-color: var(--success-color);
  border-color: var(--success-color);
}

/* ==========================================
   Navigation Bar Header
   ========================================== */
.header {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  z-index: 1000;
  background-color: rgba(var(--bg-color == #f8fafc ? '248, 250, 252' : '11, 15, 25'), 0.85);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border-color);
  transition: all var(--transition-normal);
}

.nav-container {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1.25rem 0;
}

.logo {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 1.5rem;
  font-weight: 800;
  letter-spacing: -0.03em;
}

.logo span {
  font-weight: 300;
  color: var(--primary-color);
}

.logo-icon {
  width: 32px;
  height: 24px;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.logo-icon span {
  display: block;
  height: 4px;
  background-color: var(--text-primary);
  border-radius: 2px;
}

.logo-icon span:nth-child(1) {
  width: 100%;
  background-color: var(--text-primary);
}
.logo-icon span:nth-child(2) {
  width: 70%;
  background-color: var(--primary-color);
}
.logo-icon span:nth-child(3) {
  width: 45%;
  background-color: var(--accent-color);
}

.nav-menu {
  display: flex;
  align-items: center;
  gap: 2rem;
}

.nav-link {
  font-weight: 500;
  color: var(--text-secondary);
  font-size: 0.95rem;
}

.nav-link:hover {
  color: var(--primary-color);
}

.nav-actions {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.theme-toggle {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: var(--bg-card-alt);
  color: var(--text-primary);
  font-size: 1.1rem;
  border: 1px solid var(--border-color);
}

.theme-toggle:hover {
  background-color: var(--border-color);
  color: var(--primary-color);
}

.hamburger {
  display: none;
  font-size: 1.5rem;
  color: var(--text-primary);
}

/* ==========================================
   Hero Section
   ========================================== */
.hero {
  position: relative;
  padding-top: 11rem;
  padding-bottom: 8rem;
  overflow: hidden;
}

.hero-container {
  display: grid;
  grid-template-columns: 1.1fr 0.9fr;
  gap: 4rem;
  align-items: center;
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  background-color: rgba(var(--primary-rgb), 0.1);
  color: var(--primary-color);
  padding: 0.5rem 1rem;
  border-radius: 50px;
  font-size: 0.85rem;
  font-weight: 600;
  margin-bottom: 1.5rem;
  border: 1px solid rgba(var(--primary-rgb), 0.15);
}

.hero-badge i {
  animation: pulse 2s infinite;
}

@keyframes pulse {
  0% { transform: scale(1); opacity: 0.8; }
  50% { transform: scale(1.2); opacity: 1; }
  100% { transform: scale(1); opacity: 0.8; }
}

.hero h1 {
  font-size: 3.5rem;
  line-height: 1.15;
  margin-bottom: 1.5rem;
}

.hero-lead {
  font-size: 1.2rem;
  color: var(--text-secondary);
  margin-bottom: 2rem;
  max-width: 580px;
}

.hero-search {
  display: flex;
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  padding: 0.5rem;
  margin-bottom: 3rem;
  box-shadow: var(--shadow-lg);
  max-width: 560px;
  align-items: center;
}

.search-icon {
  color: var(--text-muted);
  margin-left: 1rem;
  margin-right: 0.5rem;
  font-size: 1.1rem;
}

.hero-search input {
  flex: 1;
  border: none;
  background: transparent;
  color: var(--text-primary);
  font-size: 0.95rem;
  padding: 0.5rem;
  outline: none;
}

.hero-search input::placeholder {
  color: var(--text-muted);
}

.hero-stats {
  display: flex;
  align-items: center;
  gap: 2rem;
}

.stat-item h4 {
  font-size: 1.8rem;
  font-weight: 800;
  display: flex;
  align-items: center;
  gap: 0.25rem;
}

.star-filled {
  color: var(--warning-color);
  font-size: 1.2rem;
}

.stat-item p {
  font-size: 0.85rem;
  color: var(--text-muted);
  font-weight: 500;
}

.stat-separator {
  width: 1px;
  height: 40px;
  background-color: var(--border-color);
}

/* Hero Right: Interactive Dashboard Visual */
.hero-visual {
  position: relative;
}

.visual-wrapper {
  position: relative;
  width: 100%;
}

.ambient-glow {
  position: absolute;
  top: 5%;
  right: -5%;
  width: 350px;
  height: 350px;
  background: radial-gradient(circle, rgba(var(--primary-rgb), 0.25) 0%, rgba(0,0,0,0) 70%);
  z-index: -1;
  filter: blur(40px);
}

.dashboard-mock {
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-xl);
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.mock-header {
  background-color: var(--bg-card-alt);
  padding: 0.75rem 1.25rem;
  border-bottom: 1px solid var(--border-color);
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.mock-dots {
  display: flex;
  gap: 0.35rem;
}

.mock-dots span {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  display: inline-block;
}

.mock-dots span:nth-child(1) { background-color: var(--danger-color); }
.mock-dots span:nth-child(2) { background-color: var(--warning-color); }
.mock-dots span:nth-child(3) { background-color: var(--success-color); }

.mock-title {
  font-size: 0.8rem;
  color: var(--text-muted);
  font-weight: 500;
  letter-spacing: 0.05em;
}

.mock-body {
  display: grid;
  grid-template-columns: 140px 1fr;
  height: 380px;
}

.mock-sidebar {
  border-right: 1px solid var(--border-color);
  background-color: rgba(var(--bg-card-alt == #f1f5f9 ? '241, 245, 249' : '30, 41, 59'), 0.2);
  padding: 1.5rem 0.5rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.sidebar-item {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.75rem;
  font-weight: 600;
  padding: 0.5rem 0.75rem;
  border-radius: var(--radius-sm);
  color: var(--text-muted);
  transition: all var(--transition-fast);
}

.sidebar-item.active {
  background-color: rgba(var(--primary-rgb), 0.1);
  color: var(--primary-color);
}

.mock-content {
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
}

.content-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.user-welcome span {
  font-size: 0.7rem;
  color: var(--text-muted);
}
.user-welcome h5 {
  font-size: 0.9rem;
  font-weight: 700;
}

.progress-indicator span {
  font-size: 0.65rem;
  color: var(--text-muted);
  display: block;
  text-align: right;
  margin-bottom: 0.2rem;
}

.progress-bar-wrapper {
  width: 90px;
  height: 6px;
  background-color: var(--border-color);
  border-radius: 3px;
  overflow: hidden;
}

.progress-bar-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--primary-color), var(--accent-color));
}

.current-lesson-card {
  background-color: var(--bg-card-alt);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  padding: 1rem;
}

.card-tag {
  font-size: 0.6rem;
  font-weight: 800;
  color: var(--accent-color);
  letter-spacing: 0.05em;
  margin-bottom: 0.25rem;
}

.current-lesson-card h6 {
  font-size: 0.9rem;
  margin-bottom: 0.15rem;
}

.current-lesson-card p {
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-bottom: 0.75rem;
}

.card-footer {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.lesson-meta {
  font-size: 0.7rem;
  color: var(--text-muted);
}

.btn-mock-play {
  background-color: var(--primary-color);
  color: white;
  padding: 0.35rem 0.75rem;
  border-radius: 4px;
  font-size: 0.7rem;
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 0.3rem;
}

.btn-mock-play:hover {
  background-color: var(--primary-hover);
}

.mock-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.75rem;
}

.mock-mini-card {
  border: 1px solid var(--border-color);
  padding: 0.75rem;
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.mock-mini-card i {
  font-size: 1.1rem;
}

.mock-mini-card h6 {
  font-size: 0.75rem;
}
.mock-mini-card span {
  font-size: 0.65rem;
  color: var(--text-muted);
}

/* ==========================================
   Interactive Career Pathfinder Quiz
   ========================================== */
.pathfinder-section {
  background-color: rgba(var(--primary-rgb), 0.02);
  border-top: 1px solid var(--border-color);
  border-bottom: 1px solid var(--border-color);
}

.quiz-container {
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 3rem;
  max-width: 800px;
  margin: 0 auto;
  box-shadow: var(--shadow-xl);
  position: relative;
  overflow: hidden;
}

.quiz-progress-bar {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 6px;
  background-color: var(--border-color);
}

.quiz-progress-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--primary-color), var(--accent-color));
  transition: width var(--transition-normal);
}

.quiz-step {
  display: none;
}

.quiz-step.active {
  display: block;
  animation: fadeIn 0.4s ease-in-out;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

.quiz-question {
  font-size: 1.6rem;
  margin-bottom: 2rem;
  text-align: center;
}

.quiz-options-grid {
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
  margin-bottom: 2.5rem;
}

.quiz-option {
  display: flex;
  align-items: center;
  gap: 1.5rem;
  background-color: var(--bg-card-alt);
  border: 2px solid var(--border-color);
  border-radius: var(--radius-md);
  padding: 1.25rem;
  text-align: left;
  width: 100%;
  transition: all var(--transition-fast);
}

.quiz-option:hover {
  border-color: var(--primary-color);
  background-color: rgba(var(--primary-rgb), 0.03);
  transform: translateY(-1px);
}

.quiz-option.selected {
  border-color: var(--primary-color);
  background-color: rgba(var(--primary-rgb), 0.08);
  box-shadow: 0 0 0 4px rgba(var(--primary-rgb), 0.15);
}

.option-icon {
  width: 50px;
  height: 50px;
  border-radius: var(--radius-sm);
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  color: var(--primary-color);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.35rem;
  flex-shrink: 0;
  transition: all var(--transition-fast);
}

.quiz-option:hover .option-icon {
  background-color: var(--primary-color);
  color: white;
  border-color: var(--primary-color);
}

.option-content strong {
  display: block;
  font-size: 1.05rem;
  margin-bottom: 0.25rem;
  color: var(--text-primary);
}

.option-content p {
  font-size: 0.85rem;
  color: var(--text-secondary);
  line-height: 1.4;
}

.quiz-nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

/* Quiz Result Panel */
.result-celebration {
  text-align: center;
}

.result-checkmark {
  font-size: 3.5rem;
  color: var(--success-color);
  margin-bottom: 1.5rem;
  animation: bounceIn 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

@keyframes bounceIn {
  from { transform: scale(0.3); opacity: 0; }
  50% { transform: scale(1.1); }
  to { transform: scale(1); opacity: 1; }
}

.result-celebration h3 {
  font-size: 1.75rem;
  margin-bottom: 0.5rem;
}

.result-celebration p {
  margin-bottom: 2rem;
  font-size: 1.05rem;
}

.recommended-card {
  background-color: var(--bg-card-alt);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  padding: 1.75rem;
  max-width: 580px;
  margin: 0 auto 2.5rem auto;
  text-align: left;
  box-shadow: var(--shadow-md);
  display: grid;
  grid-template-columns: 100px 1fr;
  gap: 1.5rem;
  align-items: center;
}

.rec-badge-icon {
  width: 80px;
  height: 80px;
  border-radius: var(--radius-sm);
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2.2rem;
  color: var(--primary-color);
}

.rec-info h4 {
  font-size: 1.25rem;
  margin-bottom: 0.35rem;
}

.rec-info p {
  font-size: 0.85rem;
  line-height: 1.5;
  margin-bottom: 0.5rem;
}

.rec-meta {
  display: flex;
  gap: 1rem;
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text-muted);
}

.rec-meta span i {
  margin-right: 0.25rem;
}

.quiz-result-actions {
  display: flex;
  justify-content: center;
  gap: 1rem;
  flex-wrap: wrap;
}

/* ==========================================
   Course Catalog Section
   ========================================== */
.courses-section {
  border-bottom: 1px solid var(--border-color);
}

/* Filters and Search Bar */
.catalog-filters {
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
}

.filter-pill {
  padding: 0.5rem 1.25rem;
  border-radius: 50px;
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--text-secondary);
  background-color: var(--bg-card-alt);
  border: 1px solid var(--border-color);
}

.filter-pill:hover {
  background-color: var(--border-color);
  color: var(--text-primary);
}

.filter-pill.active {
  background-color: var(--primary-color);
  color: white;
  border-color: var(--primary-color);
  box-shadow: 0 4px 12px rgba(var(--primary-rgb), 0.2);
}

.filter-search-row {
  display: grid;
  grid-template-columns: 1fr auto;
  gap: 2rem;
  margin-bottom: 3rem;
  align-items: center;
}

.search-box {
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  padding: 0.75rem 1rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.search-box i {
  color: var(--text-muted);
}

.search-box input {
  border: none;
  background: transparent;
  width: 100%;
  color: var(--text-primary);
  font-size: 0.95rem;
  outline: none;
}

.filter-stats {
  font-size: 0.9rem;
  color: var(--text-muted);
  font-weight: 500;
}

/* Courses Cards Grid */
.courses-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(360px, 1fr));
  gap: 2.5rem;
}

.course-card {
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  overflow: hidden;
  box-shadow: var(--shadow-sm);
  display: flex;
  flex-direction: column;
  position: relative;
  transition: all var(--transition-normal);
}

.course-card:hover {
  transform: translateY(-6px);
  box-shadow: var(--shadow-xl);
  border-color: var(--primary-color);
}

.course-badge {
  position: absolute;
  top: 1rem;
  left: 1rem;
  z-index: 10;
  padding: 0.35rem 0.75rem;
  border-radius: 4px;
  font-size: 0.7rem;
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  background-color: var(--primary-color);
  color: white;
}

.course-badge.hot {
  background-color: #f97316;
}

.course-badge.new {
  background-color: #10b981;
}

.course-thumb {
  position: relative;
  width: 100%;
  padding-top: 56.25%; /* 16:9 Aspect Ratio */
  overflow: hidden;
}

.course-thumb img {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform var(--transition-slow);
}

.course-card:hover .course-thumb img {
  transform: scale(1.05);
}

.course-details {
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  flex: 1;
}

.course-meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text-muted);
  margin-bottom: 0.75rem;
}

.course-cat i {
  color: var(--primary-color);
  margin-right: 0.25rem;
}

.course-rating {
  display: flex;
  align-items: center;
  gap: 0.25rem;
}

.course-rating i {
  color: var(--warning-color);
}

.course-title {
  font-size: 1.25rem;
  margin-bottom: 0.5rem;
  line-height: 1.35;
  color: var(--text-primary);
}

.course-excerpt {
  font-size: 0.85rem;
  color: var(--text-secondary);
  margin-bottom: 1.25rem;
  line-height: 1.5;
  flex-grow: 1;
}

.course-stats-bar {
  display: flex;
  gap: 1.25rem;
  border-top: 1px solid var(--border-color);
  border-bottom: 1px solid var(--border-color);
  padding: 0.75rem 0;
  margin-bottom: 1.25rem;
  font-size: 0.75rem;
  font-weight: 500;
  color: var(--text-muted);
}

.course-stats-bar span i {
  margin-right: 0.25rem;
}

.course-instructor {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin-bottom: 1.5rem;
}

.inst-avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  object-fit: cover;
  border: 1px solid var(--border-color);
}

.course-instructor h5 {
  font-size: 0.85rem;
  font-weight: 700;
}

.course-instructor span {
  font-size: 0.7rem;
  color: var(--text-muted);
  display: block;
}

.course-pricing {
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-top: 1px solid var(--border-color);
  padding-top: 1.25rem;
}

.price-block {
  display: flex;
  align-items: baseline;
  gap: 0.5rem;
}

.current-price {
  font-size: 1.5rem;
  font-weight: 800;
  color: var(--text-primary);
}

.old-price {
  font-size: 0.9rem;
  text-decoration: line-through;
  color: var(--text-muted);
}

/* Empty Catalog State */
.no-courses-state {
  text-align: center;
  padding: 4rem 2rem;
  border: 2px dashed var(--border-color);
  border-radius: var(--radius-md);
  margin-top: 2rem;
}

.no-courses-state i {
  font-size: 3rem;
  color: var(--text-muted);
  margin-bottom: 1.5rem;
}

.no-courses-state h4 {
  font-size: 1.25rem;
  margin-bottom: 0.5rem;
}

.no-courses-state p {
  color: var(--text-muted);
  margin-bottom: 1.5rem;
}

/* ==========================================
   Flagship Curriculum Spotlight Section (Syllabus)
   ========================================== */
.syllabus-section {
  background-color: var(--bg-card-alt);
  border-bottom: 1px solid var(--border-color);
}

.syllabus-grid {
  display: grid;
  grid-template-columns: 0.9fr 1.1fr;
  gap: 5rem;
  align-items: flex-start;
}

.syllabus-text-col p {
  font-size: 1.1rem;
  margin-bottom: 2.5rem;
}

.syllabus-highlights {
  display: flex;
  flex-direction: column;
  gap: 1.75rem;
  margin-bottom: 2.5rem;
}

.highlight-item {
  display: flex;
  gap: 1.25rem;
}

.highlight-icon {
  width: 48px;
  height: 48px;
  border-radius: var(--radius-sm);
  background-color: rgba(var(--primary-rgb), 0.1);
  color: var(--primary-color);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.25rem;
  flex-shrink: 0;
}

.highlight-item h4 {
  font-size: 1.05rem;
  margin-bottom: 0.25rem;
}

.highlight-item p {
  font-size: 0.85rem;
  line-height: 1.5;
  color: var(--text-secondary);
}

.badge-checklist {
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
}

.badge-checklist span {
  font-size: 0.75rem;
  font-weight: 600;
  background-color: var(--bg-card);
  padding: 0.4rem 0.8rem;
  border-radius: 4px;
  border: 1px solid var(--border-color);
  color: var(--text-primary);
}

.badge-checklist span i {
  color: var(--success-color);
  margin-right: 0.25rem;
}

.accordion-header-info {
  margin-bottom: 1.5rem;
}

.accordion-header-info span {
  font-size: 0.75rem;
  font-weight: 700;
  text-transform: uppercase;
  color: var(--text-muted);
}

.accordion-header-info p {
  font-size: 0.85rem;
  color: var(--text-muted);
}

/* Accordion Element Styles */
.accordion-item {
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  margin-bottom: 1rem;
  overflow: hidden;
}

.accordion-item.active {
  border-color: var(--primary-color);
  box-shadow: var(--shadow-md);
}

.accordion-trigger {
  width: 100%;
  display: flex;
  align-items: center;
  padding: 1.25rem;
  text-align: left;
  justify-content: space-between;
  gap: 1rem;
  background-color: var(--bg-card);
  color: var(--text-primary);
  font-weight: 700;
}

.accordion-trigger:hover {
  background-color: rgba(var(--primary-rgb), 0.01);
}

.mod-number {
  font-size: 0.75rem;
  color: var(--primary-color);
  background-color: rgba(var(--primary-rgb), 0.1);
  padding: 0.25rem 0.5rem;
  border-radius: 4px;
  text-transform: uppercase;
  font-weight: 800;
  flex-shrink: 0;
}

.mod-title {
  font-size: 0.95rem;
  flex-grow: 1;
}

.accordion-icon {
  font-size: 0.85rem;
  color: var(--text-muted);
  transition: transform var(--transition-normal);
}

.accordion-item.active .accordion-icon {
  transform: rotate(180deg);
  color: var(--primary-color);
}

.accordion-panel {
  max-height: 0;
  overflow: hidden;
  transition: max-height var(--transition-normal) ease-out;
}

.panel-content {
  padding: 0 1.25rem 1.5rem 1.25rem;
  border-top: 1px solid var(--border-color);
}

.panel-content ul {
  display: flex;
  flex-direction: column;
  gap: 0.85rem;
  padding-top: 1rem;
}

.panel-content li {
  font-size: 0.85rem;
  color: var(--text-secondary);
  display: flex;
  align-items: flex-start;
  gap: 0.75rem;
}

.panel-content li i {
  color: var(--primary-color);
  margin-top: 0.15rem;
}

.panel-content li i.fa-circle-play {
  color: var(--text-muted);
}

.panel-content li strong {
  color: var(--text-primary);
}

.badge-time {
  margin-left: auto;
  font-size: 0.7rem;
  color: var(--text-muted);
  background-color: var(--bg-card-alt);
  padding: 0.1rem 0.4rem;
  border-radius: 2px;
  font-weight: 600;
}

/* ==========================================
   Learning Experience / Features
   ========================================== */
.learning-experience {
  border-bottom: 1px solid var(--border-color);
}

.feature-grid {
  margin-top: 4.5rem;
}

.exp-card {
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  padding: 2.5rem;
  border-radius: var(--radius-md);
  text-align: left;
  transition: all var(--transition-normal);
}

.exp-card:hover {
  transform: translateY(-5px);
  box-shadow: var(--shadow-md);
  border-color: var(--primary-color);
}

.exp-icon {
  width: 56px;
  height: 56px;
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  margin-bottom: 1.5rem;
}

.bg-light-purple {
  background-color: rgba(129, 140, 248, 0.15);
  color: #6366f1;
}

.bg-light-teal {
  background-color: rgba(34, 211, 238, 0.15);
  color: #06b6d4;
}

.bg-light-orange {
  background-color: rgba(249, 115, 22, 0.15);
  color: #f97316;
}

.exp-card h3 {
  font-size: 1.2rem;
  margin-bottom: 0.75rem;
}

.exp-card p {
  font-size: 0.9rem;
  line-height: 1.5;
}

/* ==========================================
   Pricing Section
   ========================================== */
.pricing-section {
  position: relative;
  background-color: rgba(var(--primary-rgb), 0.01);
  border-bottom: 1px solid var(--border-color);
}

.pricing-toggle-container {
  display: inline-flex;
  align-items: center;
  gap: 1rem;
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  padding: 0.4rem 1rem;
  border-radius: 50px;
  box-shadow: var(--shadow-sm);
}

.toggle-label {
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--text-muted);
}

.toggle-label.active {
  color: var(--text-primary);
}

.discount-badge {
  background-color: #10b981;
  color: white;
  padding: 0.15rem 0.5rem;
  border-radius: 50px;
  font-size: 0.65rem;
  font-weight: 800;
  text-transform: uppercase;
}

.pricing-toggle {
  width: 50px;
  height: 26px;
  background-color: var(--primary-color);
  border-radius: 50px;
  position: relative;
  padding: 2px;
}

.toggle-switch-handle {
  display: block;
  width: 22px;
  height: 22px;
  background-color: white;
  border-radius: 50%;
  position: absolute;
  top: 2px;
  left: 2px;
  transition: transform var(--transition-normal);
  box-shadow: var(--shadow-sm);
}

.pricing-toggle.active .toggle-switch-handle {
  transform: translateX(24px);
}

.pricing-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 2.5rem;
  margin-top: 4.5rem;
  align-items: flex-start;
}

.pricing-card {
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 3rem 2.5rem;
  position: relative;
  display: flex;
  flex-direction: column;
}

.pricing-card.popular {
  border-color: var(--primary-color);
  box-shadow: var(--shadow-xl);
  transform: scale(1.03);
  z-index: 2;
}

.popular-ribbon {
  position: absolute;
  top: 1.25rem;
  right: 1.25rem;
  background-color: var(--primary-color);
  color: white;
  font-size: 0.7rem;
  font-weight: 800;
  text-transform: uppercase;
  padding: 0.25rem 0.75rem;
  border-radius: 50px;
  letter-spacing: 0.05em;
}

.plan-header {
  margin-bottom: 2rem;
  border-bottom: 1px solid var(--border-color);
  padding-bottom: 1.5rem;
}

.plan-header h4 {
  font-size: 1.35rem;
  margin-bottom: 0.5rem;
}

.plan-header p {
  font-size: 0.85rem;
  color: var(--text-muted);
  line-height: 1.4;
  margin-bottom: 1.5rem;
}

.plan-price {
  display: flex;
  align-items: baseline;
  gap: 0.15rem;
}

.plan-price .currency {
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--text-primary);
}

.plan-price .price-val {
  font-size: 3.2rem;
  font-weight: 800;
  color: var(--text-primary);
  line-height: 1;
}

.plan-price .duration {
  font-size: 0.9rem;
  color: var(--text-muted);
  font-weight: 500;
}

.billing-clarification {
  display: block;
  font-size: 0.7rem;
  color: var(--text-muted);
  font-weight: 600;
  margin-top: 0.5rem;
}

.plan-body {
  margin-bottom: 2.5rem;
}

.plan-body ul {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.plan-body li {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.plan-body li.disabled {
  color: var(--text-muted);
  text-decoration: line-through;
  opacity: 0.55;
}

.plan-body li i {
  font-size: 0.9rem;
  flex-shrink: 0;
}

.plan-body li i.fa-check {
  color: var(--success-color);
}

.plan-body li i.fa-xmark {
  color: var(--danger-color);
}

.plan-footer {
  margin-top: auto;
}

/* ==========================================
   Testimonials Section
   ========================================== */
.testimonials-section {
  border-bottom: 1px solid var(--border-color);
}

.testimonials-carousel-wrapper {
  max-width: 860px;
  margin: 0 auto;
  position: relative;
}

.testimonials-container {
  position: relative;
  min-height: 320px;
}

.testimonial-slide {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  opacity: 0;
  visibility: hidden;
  transition: opacity 0.5s ease, transform 0.5s ease, visibility 0.5s;
  transform: translateX(15px);
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  padding: 3.5rem;
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-md);
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
}

.testimonial-slide.active {
  opacity: 1;
  visibility: visible;
  transform: translateX(0);
  position: relative;
}

.testimonial-rating {
  color: var(--warning-color);
  display: flex;
  gap: 0.25rem;
  margin-bottom: 1.5rem;
  font-size: 1.1rem;
}

.testimonial-quote {
  font-family: var(--font-sans);
  font-size: 1.25rem;
  font-weight: 500;
  line-height: 1.6;
  color: var(--text-primary);
  margin-bottom: 2rem;
  font-style: italic;
}

.testimonial-user {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.testimonial-avatar {
  width: 50px;
  height: 50px;
  border-radius: 50%;
  object-fit: cover;
  border: 2px solid var(--primary-color);
}

.testimonial-user h5 {
  font-size: 1rem;
  font-weight: 700;
  text-align: left;
}

.testimonial-user span {
  font-size: 0.75rem;
  color: var(--text-muted);
  display: block;
  text-align: left;
}

.carousel-controls {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 1.5rem;
  margin-top: 2rem;
}

.carousel-arrow {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  color: var(--text-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.9rem;
}

.carousel-arrow:hover {
  background-color: var(--primary-color);
  color: white;
  border-color: var(--primary-color);
}

.carousel-dots {
  display: flex;
  gap: 0.5rem;
}

.dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background-color: var(--border-color);
}

.dot.active {
  background-color: var(--primary-color);
  width: 20px;
  border-radius: 10px;
}

/* ==========================================
   FAQ Accordions Section
   ========================================== */
.faq-section {
  background-color: rgba(var(--primary-rgb), 0.01);
  border-bottom: 1px solid var(--border-color);
}

.faq-accordion-container {
  max-width: 800px;
  margin: 0 auto;
}

.faq-item {
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  margin-bottom: 1rem;
  overflow: hidden;
  transition: border var(--transition-fast);
}

.faq-item.active {
  border-color: var(--border-focus);
}

.faq-trigger {
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1.5rem;
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--text-primary);
  text-align: left;
}

.faq-trigger:hover {
  background-color: rgba(var(--primary-rgb), 0.01);
}

.faq-trigger i {
  color: var(--text-muted);
  font-size: 0.95rem;
  transition: transform var(--transition-normal);
}

.faq-item.active .faq-trigger i {
  transform: rotate(45deg);
  color: var(--primary-color);
}

.faq-panel {
  max-height: 0;
  overflow: hidden;
  transition: max-height var(--transition-normal) ease-out;
}

.faq-panel p {
  padding: 0 1.5rem 1.5rem 1.5rem;
  font-size: 0.9rem;
  line-height: 1.6;
  color: var(--text-secondary);
}

/* ==========================================
   Modals (Login & Checkout)
   ========================================== */
.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(15, 23, 42, 0.7);
  backdrop-filter: blur(8px);
  z-index: 2000;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  visibility: hidden;
  transition: opacity var(--transition-normal), visibility var(--transition-normal);
}

.modal-overlay.active {
  opacity: 1;
  visibility: visible;
}

.modal-card {
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  width: 90%;
  max-width: 580px;
  padding: 2.5rem;
  box-shadow: var(--shadow-xl);
  position: relative;
  transform: scale(0.92);
  transition: transform var(--transition-normal);
}

.modal-overlay.active .modal-card {
  transform: scale(1);
}

.modal-card.sm {
  max-width: 420px;
}

.modal-close {
  position: absolute;
  top: 1.25rem;
  right: 1.25rem;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background-color: var(--bg-card-alt);
  color: var(--text-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1rem;
}

.modal-close:hover {
  background-color: var(--border-color);
}

.modal-header {
  margin-bottom: 2rem;
}

.modal-subtitle {
  font-size: 0.75rem;
  font-weight: 700;
  color: var(--primary-color);
  text-transform: uppercase;
}

.modal-title {
  font-size: 1.5rem;
  margin-bottom: 0.25rem;
}

.modal-header p {
  font-size: 0.85rem;
}

/* Forms */
.checkout-form {
  display: flex;
  flex-direction: column;
}

.checkout-steps {
  display: flex;
  justify-content: space-between;
  border-bottom: 1px solid var(--border-color);
  padding-bottom: 0.75rem;
  margin-bottom: 1.5rem;
}

.chk-step {
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--text-muted);
}

.chk-step.active {
  color: var(--primary-color);
}

.checkout-slide {
  display: none;
}

.checkout-slide.active {
  display: block;
}

.form-group {
  margin-bottom: 1.25rem;
}

.form-group label {
  display: block;
  font-size: 0.8rem;
  font-weight: 700;
  margin-bottom: 0.4rem;
  color: var(--text-primary);
}

.form-group input {
  width: 100%;
  padding: 0.75rem 1rem;
  background-color: var(--bg-card-alt);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  font-family: inherit;
  font-size: 0.9rem;
  outline: none;
}

.form-group input:focus {
  border-color: var(--primary-color);
}

.form-row-2 {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
}

.input-with-icon {
  position: relative;
}

.input-inner-icon {
  position: absolute;
  left: 1rem;
  top: 50%;
  transform: translateY(-50%);
  color: var(--text-muted);
}

.input-with-icon input {
  padding-left: 2.5rem;
}

.modal-price-summary {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background-color: rgba(var(--primary-rgb), 0.04);
  border: 1px solid var(--border-color);
  padding: 1rem;
  border-radius: var(--radius-sm);
  margin-bottom: 1.5rem;
}

.modal-price-summary span {
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.modal-price-summary strong {
  font-size: 1.4rem;
  color: var(--text-primary);
  font-weight: 800;
}

.mock-card-warning {
  background-color: rgba(6, 182, 212, 0.08);
  border: 1px solid rgba(6, 182, 212, 0.15);
  color: var(--accent-hover);
  padding: 0.75rem 1rem;
  border-radius: var(--radius-sm);
  font-size: 0.75rem;
  display: flex;
  gap: 0.75rem;
  align-items: flex-start;
  margin-bottom: 1.25rem;
  line-height: 1.4;
}

.mock-card-warning i {
  font-size: 1rem;
  margin-top: 0.1rem;
}

.chk-actions {
  display: flex;
  gap: 1rem;
}

.chk-actions button {
  flex: 1;
}

/* ==========================================
   Toast Notifications popup
   ========================================== */
.toast-popup {
  position: fixed;
  bottom: 2rem;
  right: 2rem;
  z-index: 3000;
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-left: 5px solid var(--success-color);
  border-radius: var(--radius-sm);
  padding: 1rem 1.5rem;
  box-shadow: var(--shadow-xl);
  display: flex;
  align-items: flex-start;
  gap: 1.25rem;
  max-width: 400px;
  transform: translateY(15px);
  opacity: 0;
  visibility: hidden;
  transition: all var(--transition-normal);
}

.toast-popup.active {
  transform: translateY(0);
  opacity: 1;
  visibility: visible;
}

.toast-content {
  display: flex;
  gap: 1rem;
}

.toast-icon {
  font-size: 1.5rem;
  color: var(--success-color);
  margin-top: 0.15rem;
}

.toast-text h5 {
  font-size: 0.95rem;
  margin-bottom: 0.15rem;
}

.toast-text p {
  font-size: 0.8rem;
  line-height: 1.4;
}

.toast-close {
  color: var(--text-muted);
  font-size: 0.85rem;
}

.toast-close:hover {
  color: var(--text-primary);
}

/* ==========================================
   Newsletter Section
   ========================================== */
.newsletter-section {
  padding-bottom: 0;
}

.newsletter-card {
  background: linear-gradient(135deg, rgba(var(--primary-rgb), 0.1) 0%, rgba(var(--accent-rgb), 0.05) 100%);
  border: 1px solid var(--border-color);
  padding: 4rem;
  border-radius: var(--radius-lg);
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 3rem;
  align-items: center;
}

.newsletter-content h3 {
  font-size: 1.8rem;
  margin-bottom: 0.5rem;
}

.newsletter-content p {
  font-size: 0.95rem;
  line-height: 1.5;
}

.newsletter-form {
  display: flex;
  gap: 0.75rem;
}

.newsletter-form input {
  flex-grow: 1;
  background-color: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  padding: 0.85rem 1.25rem;
  font-family: inherit;
  color: var(--text-primary);
  outline: none;
}

.newsletter-form input:focus {
  border-color: var(--primary-color);
}

/* ==========================================
   Footer Section
   ========================================== */
.footer {
  background-color: var(--bg-card);
  border-top: 1px solid var(--border-color);
  padding-top: 6rem;
  padding-bottom: 3rem;
  margin-top: 8rem;
}

.footer-grid-columns {
  display: grid;
  grid-template-columns: 1.2fr 0.8fr 0.8fr 1.2fr;
  gap: 4rem;
  margin-bottom: 4rem;
}

.footer-brand-col p {
  font-size: 0.9rem;
  margin-top: 1rem;
  margin-bottom: 1.5rem;
  line-height: 1.6;
}

.social-row {
  display: flex;
  gap: 0.75rem;
}

.social-row a {
  width: 36px;
  height: 36px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border-color);
  background-color: var(--bg-card-alt);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.95rem;
  color: var(--text-secondary);
}

.social-row a:hover {
  background-color: var(--primary-color);
  color: white;
  border-color: var(--primary-color);
  transform: translateY(-2px);
}

.footer-links-col h3 {
  font-size: 0.95rem;
  margin-bottom: 1.5rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-primary);
}

.footer-links-col ul {
  display: flex;
  flex-direction: column;
  gap: 0.85rem;
}

.footer-links-col a {
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.footer-links-col a:hover {
  color: var(--primary-color);
}

.footer-links-col li {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.footer-links-col li i {
  color: var(--primary-color);
  font-size: 0.9rem;
}

.footer-bottom {
  border-top: 1px solid var(--border-color);
  padding-top: 2rem;
}

.flex-footer-bottom {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.bottom-legal-links {
  display: flex;
  gap: 1.5rem;
}

.bottom-legal-links a:hover {
  color: var(--primary-color);
}

/* ==========================================
   Responsive Media Queries
   ========================================== */
@media (max-width: 1100px) {
  .hero-container {
    grid-template-columns: 1fr;
    gap: 3rem;
  }
  .hero-content {
    text-align: center;
  }
  .hero-badge {
    margin-left: auto;
    margin-right: auto;
  }
  .hero-lead {
    margin-left: auto;
    margin-right: auto;
  }
  .hero-search {
    margin-left: auto;
    margin-right: auto;
  }
  .hero-stats {
    justify-content: center;
  }
  .syllabus-grid {
    grid-template-columns: 1fr;
    gap: 4rem;
  }
  .footer-grid-columns {
    grid-template-columns: 1fr 1fr;
    gap: 3rem;
  }
}

@media (max-width: 860px) {
  section {
    padding: 5rem 0;
  }
  .hamburger {
    display: block;
  }
  .nav-menu {
    position: fixed;
    top: 80px;
    left: -100%;
    width: 100%;
    height: calc(100vh - 80px);
    background-color: var(--bg-card);
    border-top: 1px solid var(--border-color);
    flex-direction: column;
    padding: 3rem 0;
    gap: 2rem;
    transition: left var(--transition-normal);
    z-index: 999;
  }
  .nav-menu.active {
    left: 0;
  }
  .nav-login-btn, .nav-cta-btn {
    display: none;
  }
  .newsletter-card {
    grid-template-columns: 1fr;
    gap: 2rem;
    padding: 2.5rem;
  }
  .filter-search-row {
    grid-template-columns: 1fr;
    gap: 1rem;
  }
  .section-header-flex {
    align-items: flex-start;
    flex-direction: column;
    gap: 1.5rem;
  }
  .testimonial-slide {
    padding: 2rem;
  }
}

@media (max-width: 600px) {
  .hero h1 {
    font-size: 2.4rem;
  }
  .section-title {
    font-size: 1.8rem;
  }
  .quiz-container {
    padding: 1.5rem;
  }
  .recommended-card {
    grid-template-columns: 1fr;
    justify-items: center;
    text-align: center;
  }
  .footer-grid-columns {
    grid-template-columns: 1fr;
    gap: 2rem;
  }
  .flex-footer-bottom {
    flex-direction: column;
    gap: 1rem;
    text-align: center;
  }
  .mock-body {
    grid-template-columns: 1fr;
    height: auto;
  }
  .mock-sidebar {
    display: none; /* Hide sidebar on small mobile dash */
  }
  .pricing-card {
    padding: 2rem 1.5rem;
  }
  .newsletter-form {
    flex-direction: column;
  }
}
