{"content":"/**
 * Zebra Academy - Premium Interactive Landing Page Logic
 */

document.addEventListener('DOMContentLoaded', () => {
  // --- CORE UI ELEMENTS ---
  const body = document.body;
  const themeToggle = document.getElementById('themeToggle');
  const themeToggleIcon = themeToggle ? themeToggle.querySelector('i') : null;
  const hamburger = document.getElementById('hamburger');
  const navMenu = document.getElementById('navMenu');

  // --- STATE MANAGERS ---
  let currentTheme = localStorage.getItem('zebra2-theme') || 'dark';

  // --- INITIALIZERS ---
  initTheme();
  initMobileMenu();
  initScrollAnimations();
  initHeroSearch();
  initPathfinderQuiz();
  initCatalogFilters();
  initSyllabusAccordions();
  initPricingToggle();
  initTestimonialCarousel();
  initFaqAccordions();
  initModals();
  initNewsletter();

  // ==========================================
  // 1. Premium Theme Switching Logic
  // ==========================================
  function initTheme() {
    // Check system preference if no stored theme
    if (!localStorage.getItem('zebra2-theme')) {
      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      currentTheme = prefersDark ? 'dark' : 'light';
    }

    setTheme(currentTheme);

    if (themeToggle) {
      themeToggle.addEventListener('click', () => {
        currentTheme = currentTheme === 'dark' ? 'light' : 'dark';
        setTheme(currentTheme);
      });
    }
  }

  function setTheme(theme) {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('zebra2-theme', theme);

    if (themeToggleIcon) {
      if (theme === 'dark') {
        themeToggleIcon.className = 'fa-solid fa-sun';
      } else {
        themeToggleIcon.className = 'fa-solid fa-moon';
      }
    }
  }

  // ==========================================
  // 2. Mobile Responsive Menu
  // ==========================================
  function initMobileMenu() {
    if (hamburger && navMenu) {
      hamburger.addEventListener('click', () => {
        navMenu.classList.toggle('active');
        const icon = hamburger.querySelector('i');
        if (navMenu.classList.contains('active')) {
          icon.className = 'fa-solid fa-xmark';
        } else {
          icon.className = 'fa-solid fa-bars';
        }
      });
    }

    // Close menu when clicking a link
    const navLinks = document.querySelectorAll('.nav-link');
    navLinks.forEach(link => {
      link.addEventListener('click', (e) => {
        e.preventDefault();
        const targetId = link.getAttribute('href');
        scrollToElement(targetId);

        if (navMenu && navMenu.classList.contains('active')) {
          navMenu.classList.remove('active');
          const icon = hamburger.querySelector('i');
          icon.className = 'fa-solid fa-bars';
        }
      });
    });
  }

  // ==========================================
  // Scroll Navigation Helper
  // ==========================================
  window.scrollToElement = function(selector) {
    const targetElement = document.querySelector(selector);
    if (targetElement) {
      const headerOffset = 80;
      const elementPosition = targetElement.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.pageYOffset - headerOffset;

      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });
    }
  };

  function initScrollAnimations() {
    // Smooth transition navbar height on scroll
    const header = document.querySelector('.header');
    window.addEventListener('scroll', () => {
      if (header) {
        if (window.scrollY > 50) {
          header.style.padding = '0.5rem 0';
          header.style.boxShadow = 'var(--shadow-md)';
        } else {
          header.style.padding = '1.25rem 0';
          header.style.boxShadow = 'none';
        }
      }
    });
  }

  // ==========================================
  // 3. Hero Search Functionality
  // ==========================================
  function initHeroSearch() {
    const searchInput = document.getElementById('heroSearchInput');
    const searchBtn = document.getElementById('heroSearchBtn');
    const catalogSearch = document.getElementById('catalogSearch');

    function executeSearch() {
      if (!searchInput) return;
      const query = searchInput.value.trim();
      if (query) {
        // Sync with course catalog search input
        if (catalogSearch) {
          catalogSearch.value = query;
          // Trigger catalog search event
          const event = new Event('input', { bubbles: true });
          catalogSearch.dispatchEvent(event);
        }

        // Scroll smoothly to catalog
        scrollToElement('#courses');
      }
    }

    if (searchBtn && searchInput) {
      searchBtn.addEventListener('click', executeSearch);
      searchInput.addEventListener('keypress', (e) => {
        if (e.key === 'Enter') executeSearch();
      });
    }
  }

  // ==========================================
  // 4. Career Pathfinder Quiz Logic
  // ==========================================
  function initPathfinderQuiz() {
    const quizStepPanels = document.querySelectorAll('.quiz-step');
    const quizProgressBar = document.getElementById('quizProgress');
    const prevBtn1 = document.getElementById('quizPrevBtn');
    const prevBtn2 = document.getElementById('quizPrevBtn2');
    const resetBtn = document.getElementById('quizResetBtn');
    const quizEnrollBtn = document.getElementById('quizEnrollBtn');
    const recommendedCard = document.getElementById('recommendedCard');

    let currentStep = 1;
    let quizAnswers = {
      goal: '',       // build, design, data
      experience: '', // beginner, intermediate, advanced
      commitment: ''  // part, full
    };

    // Course recommendation list mapping
    const coursesPool = {
      developmentBeginner: {
        title: "Full-Stack Web Development Bootcamp",
        category: "Development",
        icon: "fa-code",
        excerpt: "Master core programming, React 19, serverless API design, and databases from absolute scratch.",
        duration: "52 hours",
        lessons: "148 lessons",
        price: 129
      },
      developmentAdvanced: {
        title: "Rust Systems Programming & WebAssembly",
        category: "Development",
        icon: "fa-microchip",
        excerpt: "Write lightning-fast, secure concurrent software utilities and compile WASM targets for reactive frontends.",
        duration: "32 hours",
        lessons: "84 lessons",
        price: 119
      },
      designAll: {
        title: "Advanced UI/UX & Design Systems in Figma",
        category: "UI/UX Design",
        icon: "fa-palette",
        excerpt: "Craft nested components, variable fluid scaling, high fidelity flows, and perfect handoff kits.",
        duration: "28 hours",
        lessons: "76 lessons",
        price: 99
      },
      dataAll: {
        title: "Applied AI & Machine Learning with Python",
        category: "Data & AI",
        icon: "fa-brain",
        excerpt: "Deep neural networking models, custom LLM prompting templates, and automated analytical telemetry grids.",
        duration: "45 hours",
        lessons: "110 lessons",
        price: 149
      }
    };

    // Handle Option Selection
    const quizOptions = document.querySelectorAll('.quiz-option');
    quizOptions.forEach(option => {
      option.addEventListener('click', () => {
        const parentStep = option.closest('.quiz-step');
        const stepNum = parseInt(parentStep.dataset.step);

        // Toggle selected styling
        parentStep.querySelectorAll('.quiz-option').forEach(opt => opt.classList.remove('selected'));
        option.classList.add('selected');

        // Record Answer
        const value = option.dataset.value;
        if (stepNum === 1) quizAnswers.goal = value;
        if (stepNum === 2) quizAnswers.experience = value;
        if (stepNum === 3) quizAnswers.commitment = value;

        // Progress step
        setTimeout(() => {
          advanceQuiz(stepNum + 1);
        }, 350);
      });
    });

    // Back buttons
    if (prevBtn1) prevBtn1.addEventListener('click', () => advanceQuiz(1));
    if (prevBtn2) prevBtn2.addEventListener('click', () => advanceQuiz(2));

    if (resetBtn) {
      resetBtn.addEventListener('click', () => {
        quizAnswers = { goal: '', experience: '', commitment: '' };
        document.querySelectorAll('.quiz-option').forEach(opt => opt.classList.remove('selected'));
        advanceQuiz(1);
      });
    }

    function advanceQuiz(nextStep) {
      currentStep = nextStep;

      // Update Quiz progress bar visual
      const totalSteps = 3;
      const progressPercent = (Math.min(currentStep, totalSteps) / totalSteps) * 100;
      if (quizProgressBar) {
        quizProgressBar.style.width = `${progressPercent}%`;
      }

      // Toggle Active Slides
      quizStepPanels.forEach(step => {
        step.classList.remove('active');
        if (parseInt(step.dataset.step) === currentStep) {
          step.classList.add('active');
        }
      });

      // Special handling if moving to recommendation result step
      if (currentStep === 4) {
        const resultStep = document.getElementById('quizResultStep');
        if (resultStep) resultStep.classList.add('active');
        calculateRecommendation();
      }
    }

    function calculateRecommendation() {
      let recommendation;

      // Rule Engine:
      if (quizAnswers.goal === 'build') {
        if (quizAnswers.experience === 'beginner') {
          recommendation = coursesPool.developmentBeginner;
        } else {
          recommendation = coursesPool.developmentAdvanced;
        }
      } else if (quizAnswers.goal === 'design') {
        recommendation = coursesPool.designAll;
      } else {
        // data goal
        recommendation = coursesPool.dataAll;
      }

      // Populate recomended card markup
      if (recommendedCard && recommendation) {
        recommendedCard.innerHTML = `
          <div class="rec-badge-icon">
            <i class="fa-solid ${recommendation.icon}"></i>
          </div>
          <div class="rec-info">
            <span class="section-subtitle">${recommendation.category}</span>
            <h4>${recommendation.title}</h4>
            <p>${recommendation.excerpt}</p>
            <div class="rec-meta">
              <span><i class="fa-regular fa-clock"></i> ${recommendation.duration}</span>
              <span><i class="fa-solid fa-layer-group"></i> ${recommendation.lessons}</span>
              <span class="text-gradient"><strong>$${recommendation.price}</strong> (15% off included)</span>
            </div>
          </div>
        `;

        // Configure Enroll CTA with discounts
        if (quizEnrollBtn) {
          const discountedPrice = Math.round(recommendation.price * 0.85); // 15% discount
          quizEnrollBtn.setAttribute('data-course', recommendation.title);
          quizEnrollBtn.setAttribute('data-price', discountedPrice);
          quizEnrollBtn.innerHTML = `Enroll in Bootcamp for only $${discountedPrice} <i class="fa-solid fa-arrow-right"></i>`;
        }
      }
    }

    if (quizEnrollBtn) {
      quizEnrollBtn.addEventListener('click', () => {
        const title = quizEnrollBtn.getAttribute('data-course');
        const price = quizEnrollBtn.getAttribute('data-price');
        openCheckoutModal(title, price);
      });
    }
  }

  // ==========================================
  // 5. Course Catalog Filtering & Dynamic Search
  // ==========================================
  function initCatalogFilters() {
    const filterPills = document.querySelectorAll('.filter-pill');
    const catalogSearch = document.getElementById('catalogSearch');
    const courseCards = document.querySelectorAll('.course-card');
    const visibleCountSpan = document.getElementById('visibleCoursesCount');
    const totalCountSpan = document.getElementById('totalCoursesCount');
    const noCoursesState = document.getElementById('noCoursesState');
    const resetCatalogBtn = document.getElementById('resetCatalogFiltersBtn');

    let activeFilter = 'all';
    let searchQuery = '';

    if (totalCountSpan) {
      totalCountSpan.textContent = courseCards.length;
    }

    // Filter Pill Clicks
    filterPills.forEach(pill => {
      pill.addEventListener('click', () => {
        filterPills.forEach(p => p.classList.remove('active'));
        pill.classList.add('active');

        activeFilter = pill.getAttribute('data-filter');
        filterAndSearchCatalog();
      });
    });

    // Real-time keyboard search input
    if (catalogSearch) {
      catalogSearch.addEventListener('input', (e) => {
        searchQuery = e.target.value.toLowerCase().trim();
        filterAndSearchCatalog();
      });
    }

    if (resetCatalogBtn) {
      resetCatalogBtn.addEventListener('click', () => {
        // Reset Search
        if (catalogSearch) catalogSearch.value = '';
        searchQuery = '';

        // Reset Filter Pill
        filterPills.forEach(p => p.classList.remove('active'));
        const allPill = Array.from(filterPills).find(p => p.getAttribute('data-filter') === 'all');
        if (allPill) allPill.classList.add('active');
        activeFilter = 'all';

        filterAndSearchCatalog();
      });
    }

    function filterAndSearchCatalog() {
      let visibleCount = 0;

      courseCards.forEach(card => {
        const category = card.getAttribute('data-category');
        const tags = card.getAttribute('data-tags') || '';
        const title = card.querySelector('.course-title').textContent.toLowerCase();
        const excerpt = card.querySelector('.course-excerpt').textContent.toLowerCase();

        // 1. Category Matching
        const matchesCategory = activeFilter === 'all' || category === activeFilter;

        // 2. Search query matching
        const matchesSearch = searchQuery === '' || 
                              title.includes(searchQuery) || 
                              excerpt.includes(searchQuery) ||
                              tags.includes(searchQuery);

        if (matchesCategory && matchesSearch) {
          card.classList.remove('hide');
          visibleCount++;
        } else {
          card.classList.add('hide');
        }
      });

      // Update visibility badge count
      if (visibleCountSpan) {
        visibleCountSpan.textContent = visibleCount;
      }

      // Show empty state if nothing matches
      if (noCoursesState) {
        if (visibleCount === 0) {
          noCoursesState.classList.remove('hide');
        } else {
          noCoursesState.classList.add('hide');
        }
      }
    }
  }

  // ==========================================
  // 6. Interactive Syllabus Accordions
  // ==========================================
  function initSyllabusAccordions() {
    const accordions = document.querySelectorAll('.accordion-item');

    accordions.forEach(item => {
      const trigger = item.querySelector('.accordion-trigger');
      const panel = item.querySelector('.accordion-panel');

      if (trigger && panel) {
        trigger.addEventListener('click', () => {
          const isActive = item.classList.contains('active');

          // Close all accordions first for pristine visual accordion UX
          accordions.forEach(otherItem => {
            otherItem.classList.remove('active');
            otherItem.querySelector('.accordion-panel').style.maxHeight = null;
            otherItem.querySelector('.accordion-trigger').setAttribute('aria-expanded', 'false');
          });

          // If it wasn't active, expand it
          if (!isActive) {
            item.classList.add('active');
            trigger.setAttribute('aria-expanded', 'true');
            panel.style.maxHeight = panel.scrollHeight + 'px';
          }
        });
      }
    });
  }

  // ==========================================
  // 7. Dynamic Subscription Plan Toggle Switch
  // ==========================================
  function initPricingToggle() {
    const billingToggle = document.getElementById('billingToggle');
    const proPrice = document.getElementById('proPrice');
    const teamPrice = document.getElementById('teamPrice');
    const proDuration = document.getElementById('proDuration');
    const teamDuration = document.getElementById('teamDuration');
    const proClarification = document.getElementById('proClarification');
    const teamClarification = document.getElementById('teamClarification');

    const billMonthlyLabel = document.getElementById('billMonthlyLabel');
    const billAnnuallyLabel = document.getElementById('billAnnuallyLabel');

    let isAnnual = true; // Annual billing by default

    if (billingToggle) {
      // Set initial switch handle position
      billingToggle.classList.add('active');

      billingToggle.addEventListener('click', () => {
        isAnnual = !isAnnual;

        if (isAnnual) {
          billingToggle.classList.add('active');
          billAnnuallyLabel.classList.add('active');
          billMonthlyLabel.classList.remove('active');

          // Animate and set annual pricing values
          animatePricingUpdate(proPrice, proPrice.dataset.annually);
          animatePricingUpdate(teamPrice, teamPrice.dataset.annually);

          if (proDuration) proDuration.textContent = '/ month';
          if (teamDuration) teamDuration.textContent = '/ dev / mo';
          if (proClarification) proClarification.textContent = 'Billed annually ($276)';
          if (teamClarification) teamClarification.textContent = 'Billed annually (min 5 members)';
        } else {
          billingToggle.classList.remove('active');
          billAnnuallyLabel.classList.remove('active');
          billMonthlyLabel.classList.add('active');

          // Animate and set monthly pricing values
          animatePricingUpdate(proPrice, proPrice.dataset.monthly);
          animatePricingUpdate(teamPrice, teamPrice.dataset.monthly);

          if (proDuration) proDuration.textContent = '/ month';
          if (teamDuration) teamDuration.textContent = '/ dev / mo';
          if (proClarification) proClarification.textContent = 'Billed monthly ($29)';
          if (teamClarification) teamClarification.textContent = 'Billed monthly (min 5 members)';
        }
      });
    }

    function animatePricingUpdate(element, targetValue) {
      if (!element) return;
      element.style.transform = 'scale(0.85)';
      element.style.opacity = '0';

      setTimeout(() => {
        element.textContent = targetValue;
        element.style.transform = 'scale(1)';
        element.style.opacity = '1';
      }, 150);
    }
  }

  // ==========================================
  // 8. Testimonials Carousel / Slider
  // ==========================================
  function initTestimonialCarousel() {
    const slides = document.querySelectorAll('.testimonial-slide');
    const dots = document.querySelectorAll('.carousel-dots .dot');
    const prevBtn = document.getElementById('carouselPrev');
    const nextBtn = document.getElementById('carouselNext');

    let currentIndex = 0;
    let autoplayTimer;

    function showSlide(index) {
      // Loop wrapping
      if (index >= slides.length) index = 0;
      if (index < 0) index = slides.length - 1;

      currentIndex = index;

      // Toggle active states
      slides.forEach((slide, i) => {
        slide.classList.remove('active');
        if (i === currentIndex) {
          slide.classList.add('active');
        }
      });

      dots.forEach((dot, i) => {
        dot.classList.remove('active');
        if (i === currentIndex) {
          dot.classList.add('active');
        }
      });

      resetAutoplay();
    }

    // Manual arrows clicks
    if (prevBtn) prevBtn.addEventListener('click', () => showSlide(currentIndex - 1));
    if (nextBtn) nextBtn.addEventListener('click', () => showSlide(currentIndex + 1));

    // Dot indicators clicks
    dots.forEach((dot, i) => {
      dot.addEventListener('click', () => showSlide(i));
    });

    // Autoplay Timer
    function startAutoplay() {
      autoplayTimer = setInterval(() => {
        showSlide(currentIndex + 1);
      }, 6500);
    }

    function resetAutoplay() {
      clearInterval(autoplayTimer);
      startAutoplay();
    }

    startAutoplay();
  }

  // ==========================================
  // 9. Frequently Asked Questions Accordions
  // ==========================================
  function initFaqAccordions() {
    const faqItems = document.querySelectorAll('.faq-item');

    faqItems.forEach(item => {
      const trigger = item.querySelector('.faq-trigger');
      const panel = item.querySelector('.faq-panel');

      if (trigger && panel) {
        trigger.addEventListener('click', () => {
          const isActive = item.classList.contains('active');

          // Close active ones (Optional, but looks cleaner)
          faqItems.forEach(otherItem => {
            otherItem.classList.remove('active');
            otherItem.querySelector('.faq-panel').style.maxHeight = null;
          });

          if (!isActive) {
            item.classList.add('active');
            panel.style.maxHeight = panel.scrollHeight + 'px';
          }
        });
      }
    });
  }

  // ==========================================
  // 10. Multi-Step Checkout Modal & Sign In Logic
  // ==========================================
  let selectedPlanTitle = '';
  let selectedPlanPrice = '';

  const checkoutModal = document.getElementById('checkoutModal');
  const modalCloseBtn = document.getElementById('modalCloseBtn');
  const modalCourseTitle = document.getElementById('modalCourseTitle');
  const modalStep1Price = document.getElementById('modalStep1Price');
  const modalStep2Price = document.getElementById('modalStep2Price');

  const loginBtn = document.getElementById('loginBtn');
  const loginModal = document.getElementById('loginModal');
  const loginCloseBtn = document.getElementById('loginCloseBtn');
  const loginForm = document.getElementById('loginForm');

  // Checkout slide controls
  const chkStep1 = document.getElementById('chkStep1');
  const chkStep2 = document.getElementById('chkStep2');
  const chkStep1Label = document.getElementById('chkStep1Label');
  const chkStep2Label = document.getElementById('chkStep2Label');

  const chkNextBtn = document.getElementById('chkNextBtn');
  const chkBackBtn = document.getElementById('chkBackBtn');
  const checkoutForm = document.getElementById('checkoutForm');

  function initModals() {
    // Attach checkout openers to ALL Course Enroll and Pricing buttons
    const buyButtons = document.querySelectorAll('.buy-course-btn, .subscribe-btn');
    buyButtons.forEach(btn => {
      btn.addEventListener('click', () => {
        let title, price;

        if (btn.classList.contains('buy-course-btn')) {
          title = btn.getAttribute('data-course');
          price = btn.getAttribute('data-price');
        } else {
          // Subscribe buttons
          title = btn.getAttribute('data-plan');
          const priceValueSpan = btn.closest('.pricing-card').querySelector('.price-val');
          const billingDurationSpan = btn.closest('.pricing-card').querySelector('.duration');
          price = priceValueSpan.textContent + billingDurationSpan.textContent;
        }

        openCheckoutModal(title, price);
      });
    });

    // Close checkout
    if (modalCloseBtn && checkoutModal) {
      modalCloseBtn.addEventListener('click', closeCheckoutModal);
    }

    // Modal slide step 1 validation and move to step 2
    if (chkNextBtn) {
      chkNextBtn.addEventListener('click', () => {
        const nameInput = document.getElementById('chkName');
        const emailInput = document.getElementById('chkEmail');
        const passInput = document.getElementById('chkPassword');

        // Basic validation check
        if (nameInput.checkValidity() && emailInput.checkValidity() && passInput.checkValidity()) {
          chkStep1.classList.remove('active');
          chkStep2.classList.add('active');
          chkStep1Label.classList.remove('active');
          chkStep2Label.classList.add('active');
        } else {
          // Trigger browsers inline errors
          nameInput.reportValidity() || emailInput.reportValidity() || passInput.reportValidity();
        }
      });
    }

    // Back button checkout modal
    if (chkBackBtn) {
      chkBackBtn.addEventListener('click', () => {
        chkStep2.classList.remove('active');
        chkStep1.classList.add('active');
        chkStep2Label.classList.remove('active');
        chkStep1Label.classList.add('active');
      });
    }

    // Checkout Form Submit (Mock checkout transition)
    if (checkoutForm) {
      checkoutForm.addEventListener('submit', (e) => {
        e.preventDefault();

        const submitBtn = document.getElementById('chkSubmitBtn');
        const originalText = submitBtn.innerHTML;
        submitBtn.disabled = true;
        submitBtn.innerHTML = `<i class="fa-solid fa-circle-notch fa-spin"></i> Processing Secure Payment...`;

        // Simulate secure validation lag
        setTimeout(() => {
          closeCheckoutModal();
          submitBtn.disabled = false;
          submitBtn.innerHTML = originalText;

          showToast(
            "Enrollment Confirmed! 🎉",
            `Welcome to Zebra Academy! We sent your access link and receipt to ${document.getElementById('chkEmail').value}.`
          );

          // Reset checkout slides
          checkoutForm.reset();
          chkStep2.classList.remove('active');
          chkStep1.classList.add('active');
          chkStep2Label.classList.remove('active');
          chkStep1Label.classList.add('active');
        }, 2200);
      });
    }

    // Sign In Modal
    if (loginBtn && loginModal) {
      loginBtn.addEventListener('click', () => {
        loginModal.classList.add('active');
      });
    }
    if (loginCloseBtn && loginModal) {
      loginCloseBtn.addEventListener('click', () => {
        loginModal.classList.remove('active');
      });
    }
    if (loginForm && loginModal) {
      loginForm.addEventListener('submit', (e) => {
        e.preventDefault();
        const email = document.getElementById('loginEmail').value;
        loginModal.classList.remove('remove');
        setTimeout(() => {
          loginModal.classList.remove('active');
          loginForm.reset();
          showToast("Welcome back!", `Alex Rivera has successfully authenticated under ${email}.`);
        }, 300);
      });
    }

    // Outside clicks close modal
    window.addEventListener('click', (e) => {
      if (e.target === checkoutModal) closeCheckoutModal();
      if (e.target === loginModal) loginModal.classList.remove('active');
    });
  }

  function openCheckoutModal(title, price) {
    selectedPlanTitle = title;
    selectedPlanPrice = price;

    if (modalCourseTitle) modalCourseTitle.textContent = title;

    // Setup prices tags
    const priceFormatted = price.includes('$') || price.includes('/') ? price : `$${price}`;
    if (modalStep1Price) modalStep1Price.textContent = priceFormatted;
    if (modalStep2Price) modalStep2Price.textContent = priceFormatted;

    if (checkoutModal) checkoutModal.classList.add('active');
  }

  function closeCheckoutModal() {
    if (checkoutModal) checkoutModal.classList.remove('active');
  }

  // ==========================================
  // 11. Custom Success Toast Notifications
  // ==========================================
  const toastNotification = document.getElementById('toastNotification');
  const toastCloseBtn = document.getElementById('toastCloseBtn');
  const toastTitle = document.getElementById('toastTitle');
  const toastMessage = document.getElementById('toastMessage');

  function showToast(title, message) {
    if (toastTitle) toastTitle.textContent = title;
    if (toastMessage) toastMessage.textContent = message;

    if (toastNotification) {
      toastNotification.classList.add('active');

      // Auto close after 7 seconds
      setTimeout(() => {
        toastNotification.classList.remove('active');
      }, 7000);
    }
  }

  if (toastCloseBtn && toastNotification) {
    toastCloseBtn.addEventListener('click', () => {
      toastNotification.classList.remove('active');
    });
  }

  // ==========================================
  // 12. Newsletter Form Submission
  // ==========================================
  function initNewsletter() {
    const newsletterForm = document.getElementById('newsletterForm');
    const newsletterEmailInput = document.getElementById('newsletterEmailInput');

    if (newsletterForm) {
      newsletterForm.addEventListener('submit', (e) => {
        e.preventDefault();
        const email = newsletterEmailInput ? newsletterEmailInput.value : '';

        showToast(
          "Subscribed Successfully! 📬", 
          `Excellent choice! We have registered ${email} for our weekly layout guides and tech reports.`
        );

        newsletterForm.reset();
      });
    }
  }
});
